package com.example.webviewwrapper

import android.Manifest
import android.content.pm.PackageManager
import android.os.Bundle
import android.webkit.*
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import kotlinx.android.synthetic.main.activity_main.*

class MainActivity : AppCompatActivity() {

    private val webView: WebView by lazy {
        webview.apply {
            settings.javaScriptEnabled = true
            addJavascriptInterface(WebAppInterface(this@MainActivity), "Android")
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView.loadUrl("https://your-web-app-url.com")

        requestCameraPermission()
    }

    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            // Permission granted, proceed with camera access
        } else {
            // Permission denied, show a message to the user
        }
    }

    private fun requestCameraPermission() {
        if (ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.CAMERA
            ) != PackageManager.PERMISSION_GRANTED
        ) {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    inner class WebAppInterface(private val activity: MainActivity) {

        @JavascriptInterface
        fun accessCamera() {
            if (ContextCompat.checkSelfPermission(
                    this@MainActivity,
                    Manifest.permission.CAMERA
                ) == PackageManager.PERMISSION_GRANTED
            ) {
                // Code to access camera
            } else {
                requestCameraPermission()
            }
        }

        @JavascriptInterface
        fun storeData(key: String, value: String) {
            activity.getSharedPreferences("webview_prefs", MODE_PRIVATE)
                .edit()
                .putString(key, value)
                .apply()
        }

        @JavascriptInterface
        fun retrieveData(key: String): String? {
            return activity.getSharedPreferences("webview_prefs", MODE_PRIVATE)
                .getString(key, null)
        }
    }
}